def legendre_symbol(a, p):
    res = 1
    a %= p

    while a != 0:
        if a == 1:
            return res

        while a % 2 == 0:
            a //= 2
            if p % 8 == 3 or p % 8 == 5:
                res = -res

        if a % 4 == 3 and p % 4 == 3:
            res = -res

        a, p = p % a, a

    return 0
